// import logo from "./logo.svg";
import "./App.css";
import CounterTop from "./components/counterPages";
import { BrowserRouter, Routes, Route, Link, useNavigate, navigate, Redirect} from "react-router-dom";
import React, { Component } from "react";


// manages view

function App() {
let navigate = useNavigate();

    return (
      <BrowserRouter>
      <div>
        <Routes>
          <Route path="/counters">
      <CounterTop nav = {navigate}></CounterTop>
      </Route>
      </Routes>
      </div>
      </BrowserRouter>
    );


}

export default App;
